// // This module splits a 16-bit input into two 8-bit parts, subtracts them, and outputs the difference times two.
module top_module(
  input wire [15:0] in,
  output reg [15:0] out
);reg [7:0] upper_byte;
  reg [7:0] lower_byte;
  reg [15:0] sum;

  always @(*) begin
    upper_byte = in[15:8];
    lower_byte = in[7:0];
    sum = upper_byte + lower_byte;
    out = sum * 2;
  end

endmodule
